module traffic_light(
    input rst_n, clk, pass_request,
    output reg red, yellow, green,
    output reg [7:0] clock
);

    localparam GREEN_TIME = 60;
    localparam YELLOW_TIME = 5;
    localparam RED_TIME = 10;

    reg [7:0] timer;
    reg [2:0] state;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            timer <= 0;
            state <= 0;
            red <= 0;
            yellow <= 0;
            green <= 0;
            clock <= 0;
        end else begin
            case (state)
                0: begin // Green state
                    if (timer == 0) begin
                        state <= 1; // Transition to Yellow
                        timer <= YELLOW_TIME;
                        yellow <= 1;
                    end else begin
                        timer <= timer - 1;
                        green <= 1;
                    end
                end
                1: begin // Yellow state
                    if (timer == 0) begin
                        state <= 2; // Transition to Red
                        timer <= RED_TIME;
                        red <= 1;
                    end else begin
                        timer <= timer - 1;
                        yellow <= 1;
                    end
                end
                2: begin // Red state
                    if (timer == 0) begin
                        state <= 0; // Transition to Green
                        timer <= GREEN_TIME;
                        green <= 1;
                    end else begin
                        timer <= timer - 1;
                        red <= 1;
                    end
                end
            endcase

            if (pass_request && timer > 10) begin
                timer <= 10;
                state <= 1;
                yellow <= 1;
            end

            clock <= timer;
        end
    end

endmodule
